messages.content:
You are an interface derivation agent. Given a frozen Stage 1 decomposition, your task is to derive precise typed interfaces for each child.

RULES:
1. You MUST NOT add, delete, rename, or reorder children. The child list from Stage 1 is LOCKED.
2. You MUST NOT change any Stage 1 field (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role).
3. Derive ONLY interface fields.
4. Separate parent-call parameters from internal leaf resource access.

REQUIRED INTERFACE CATEGORIES:
- call_inputs: Parameters the parent must pass when calling this child. Only these may appear in the Python signature.
- internal_leaf_accesses: Resources/data stores this child accesses inside its own implementation. These must NOT appear in the Python signature.
- outputs: Values returned by the child to the parent.
- signature: Python function signature built only from call_inputs.

DATAFLOW RULES:
- from_node and to_node must be either "parent" or an exact child name.
- Resource/store names such as raw_data, processed_data, channels, messages, orders, inventory, or payments must NOT appear as from_node/to_node.

OUTPUT FORMAT — Return valid JSON:
{
  "children": [
    {
      "name": "UNCHANGED from Stage 1",
      "purpose": "UNCHANGED",
      "behavior": "UNCHANGED",
      "boundary": {"in_scope": ["UNCHANGED"], "out_of_scope": ["UNCHANGED"]},
      "semantic_inputs": ["UNCHANGED"],
      "semantic_outputs": ["UNCHANGED"],
      "preconditions": ["UNCHANGED"],
      "postconditions": ["UNCHANGED"],
      "guarantees": ["UNCHANGED"],
      "composition_role": "UNCHANGED",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {"name": "param", "type": "dict", "description": "what parent passes", "source": "parent input | previous child output | constant"}
      ],
      "internal_leaf_accesses": [
        {"resource": "resource_name", "op": "read|write|read_write", "reason": "why this child needs the resource internally"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "what child returns", "consumer": "parent"}
      ],
      "signature": "def ChildName(param: type) -> return_type"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {"input_name": "child_name"},
    "parent_outputs_produced_by": {"output_name": "child_name"}
  },
  "dataflow_edges": [
    {"from_node": "parent | ChildName", "from_output": "output_name", "to_node": "ChildName | parent", "to_input": "input_name", "note": "why"}
  ],
  "interface_audit": {
    "identity_preservation_detail": "explain whether child names/order are preserved",
    "semantic_preservation_detail": "explain whether Stage1 semantics are unchanged",
    "call_signature_detail": "explain why signature contains only call_inputs",
    "internal_leaf_separation_detail": "explain why resources are not call params",
    "dataflow_schema_detail": "explain endpoint legality",
    "final_status": "ok | needs_attention"
  }
}

{
  "children": [
    {
      "name": "ParseAndValidateInput",
      "purpose": "Parse the input JSON and validate the command field",
      "behavior": "Parse input JSON, check if command is one of allowed values, return parsed command and payload",
      "boundary": {
        "in_scope": [
          "JSON parsing",
          "command validation"
        ],
        "out_of_scope": [
          "executing commands",
          "data access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "Raw JSON input",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "parsed_command",
          "description": "Validated command string",
          "consumer": "parent"
        },
        {
          "name": "payload",
          "description": "Remaining fields after command extraction",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input is valid JSON"
      ],
      "postconditions": [
        "command is one of send/history/create_channel/join"
      ],
      "guarantees": [
        "Returns error if command missing or invalid"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "SendMessage",
      "purpose": "Send a message to a channel the user has joined",
      "behavior": "Check if user is member of channel, then store message in messages store",
      "boundary": {
        "in_scope": [
          "message storage",
          "membership check"
        ],
        "out_of_scope": [
          "channel creation",
          "history retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains user, channel, text",
          "source": "parent input"
        },
        {
          "name": "channels",
          "description": "Channel data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "channel exists",
        "user is member"
      ],
      "postconditions": [
        "message stored with timestamp"
      ],
      "guarantees": [
        "Message not stored if user not member"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetHistory",
      "purpose": "Retrieve last 100 messages from a channel the user has joined",
      "behavior": "Check membership, then query messages store for channel, limit to 100",
      "boundary": {
        "in_scope": [
          "message retrieval",
          "membership check"
        ],
        "out_of_scope": [
          "message sending",
          "channel management"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains user, channel",
          "source": "parent input"
        },
        {
          "name": "messages",
          "description": "Message data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "List of messages or error",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "channel exists",
        "user is member"
      ],
      "postconditions": [
        "Returns at most 100 messages"
      ],
      "guarantees": [
        "Returns error if not member"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CreateChannel",
      "purpose": "Create a new channel and add creator as member",
      "behavior": "Check if channel name already exists, if not create and add user to members list",
      "boundary": {
        "in_scope": [
          "channel creation",
          "membership initialization"
        ],
        "out_of_scope": [
          "message operations",
          "joining existing channels"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel name, user",
          "source": "parent input"
        },
        {
          "name": "channels",
          "description": "Channel data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "channel name not empty"
      ],
      "postconditions": [
        "channel exists with creator as member"
      ],
      "guarantees": [
        "Returns error if channel already exists"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "JoinChannel",
      "purpose": "Add user to an existing channel's member list",
      "behavior": "Check if channel exists and user not already member, then add user",
      "boundary": {
        "in_scope": [
          "membership addition"
        ],
        "out_of_scope": [
          "channel creation",
          "message operations"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel name, user",
          "source": "parent input"
        },
        {
          "name": "channels",
          "description": "Channel data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "channel exists"
      ],
      "postconditions": [
        "user added to channel members"
      ],
      "guarantees": [
        "Returns error if already member or channel missing"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The parent ChatApp handles four distinct commands. Each command is decomposed into a separate child function that performs the specific operation. Additionally, a validation child parses and validates the input before routing to the appropriate command handler. This keeps each child focused on a single responsibility.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "ParseAndValidateInput",
      "data": "input",
      "note": "Raw input for parsing"
    },
    {
      "from": "ParseAndValidateInput",
      "to": "parent",
      "data": "parsed_command, payload",
      "note": "Validated command and payload"
    },
    {
      "from": "parent",
      "to": "SendMessage",
      "data": "payload",
      "note": "If command is send"
    },
    {
      "from": "parent",
      "to": "GetHistory",
      "data": "payload",
      "note": "If command is history"
    },
    {
      "from": "parent",
      "to": "CreateChannel",
      "data": "payload",
      "note": "If command is create_channel"
    },
    {
      "from": "parent",
      "to": "JoinChannel",
      "data": "payload",
      "note": "If command is join"
    },
    {
      "from": "SendMessage",
      "to": "parent",
      "data": "result",
      "note": "Response"
    },
    {
      "from": "GetHistory",
      "to": "parent",
      "data": "result",
      "note": "Response"
    },
    {
      "from": "CreateChannel",
      "to": "parent",
      "data": "result",
      "note": "Response"
    },
    {
      "from": "JoinChannel",
      "to": "parent",
      "data": "result",
      "note": "Response"
    }
  ]
}
